1	/**
2	 * Mixer panel with horizontal channel strips.
3	 * Reads track state from Zustand store.
4	 * Metering is driven by canvas rAF loop (NFR-13) via useMeterData hook
5	 * reading real AnalyserNode data from the mixer engine.
6	 */
7	
8	import { useCallback } from "react";
9	import { useDawStore } from "@state/store";
10	import { ChannelStrip } from "./ChannelStrip";
11	import { MasterStrip } from "./MasterStrip";
12	import { useMeterData } from "./useMeterData";
13	import styles from "./MixerPanel.module.css";
14	
15	export function MixerPanel(): React.JSX.Element {
16	  const tracks = useDawStore((s) => s.tracks);
17	  const masterVolume = useDawStore((s) => s.masterVolume);
18	  const updateTrack = useDawStore((s) => s.updateTrack);
19	  const setMasterVolume = useDawStore((s) => s.setMasterVolume);
20	  const meters = useMeterData();
21	
22	  const handleVolumeChange = useCallback(
23	    (trackId: string, volume: number) => {
24	      updateTrack(trackId, { volume });
25	    },
26	    [updateTrack],
27	  );
28	
29	  const handlePanChange = useCallback(
30	    (trackId: string, pan: number) => {
31	      updateTrack(trackId, { pan });
32	    },
33	    [updateTrack],
34	  );
35	
36	  const handleMuteToggle = useCallback(
37	    (trackId: string) => {
38	      const track = useDawStore.getState().tracks.find((t) => t.id === trackId);
39	      if (track) updateTrack(trackId, { muted: !track.muted });
40	    },
41	    [updateTrack],
42	  );
43	
44	  const handleSoloToggle = useCallback(
45	    (trackId: string) => {
46	      const track = useDawStore.getState().tracks.find((t) => t.id === trackId);
47	      if (track) updateTrack(trackId, { solo: !track.solo });
48	    },
49	    [updateTrack],
50	  );
51	
52	  return (
53	    <section data-testid="mixer-panel" className={styles["mixer"]}>
54	      {tracks.map((track) => (
55	        <ChannelStrip
56	          key={track.id}
57	          trackId={track.id}
58	          name={track.name}
59	          color={track.color}
60	          volume={track.volume}
61	          pan={track.pan}
62	          muted={track.muted}
63	          solo={track.solo}
64	          meterLevel={meters.channels[track.id]?.level ?? 0}
65	          meterPeak={meters.channels[track.id]?.peak ?? 0}
66	          clipping={meters.channels[track.id]?.clipping ?? false}
67	          onVolumeChange={handleVolumeChange}
68	          onPanChange={handlePanChange}
69	          onMuteToggle={handleMuteToggle}
70	          onSoloToggle={handleSoloToggle}
71	        />
72	      ))}
73	      <MasterStrip
74	        volume={masterVolume}
75	        meterLevel={meters.master.level}
76	        meterPeak={meters.master.peak}
77	        clipping={meters.master.clipping}
78	        onVolumeChange={setMasterVolume}
79	      />
80	    </section>
81	  );
82	}
