1	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
2	import type {
3	  MediaPool,
4	  WaveformPeaks,
5	  MediaPoolError,
6	} from "@audio/media-pool";
7	import { MediaPoolItem } from "./MediaPoolItem";
8	import { useFileDrop } from "./useFileDrop";
9	import { Spinner } from "@ui/primitives/Spinner";
10	import styles from "./MediaPoolPanel.module.css";
11	
12	type MediaPoolPanelProps = {
13	  pool: MediaPool;
14	};
15	
16	function formatError(error: MediaPoolError): string {
17	  switch (error.kind) {
18	    case "decode-failed":
19	      return `Failed to decode "${error.fileName}". Try WAV, MP3, OGG, or FLAC format.`;
20	    case "unsupported-format":
21	      return `Unsupported format: "${error.fileName}". Try WAV, MP3, OGG, or FLAC.`;
22	    case "file-too-large":
23	      return `File "${error.fileName}" is too large (max 500MB).`;
24	    case "storage-full":
25	      return `Storage full. Cannot import "${error.fileName}".`;
26	  }
27	}
28	
29	export function MediaPoolPanel({
30	  pool,
31	}: MediaPoolPanelProps): React.JSX.Element {
32	  const fileInputRef = useRef<HTMLInputElement>(null);
33	  const [version, setVersion] = useState(0);
34	  const sources = useMemo(() => pool.listSources(), [pool, version]); // eslint-disable-line react-hooks/exhaustive-deps
35	  const [peaksMap, setPeaksMap] = useState(new Map<string, WaveformPeaks>());
36	  const [errors, setErrors] = useState<MediaPoolError[]>([]);
37	  const [isImporting, setIsImporting] = useState(false);
38	  const importingRef = useRef(false);
39	
40	  useEffect(() => {
41	    // Load cached peaks for persisted sources
42	    void Promise.all(
43	      sources.map(async (source) => {
44	        if (peaksMap.has(source.id)) return;
45	        const peaks = await pool.getPeaks(source.id, 256);
46	        if (peaks !== undefined) {
47	          setPeaksMap((prev) => {
48	            const next = new Map(prev);
49	            next.set(source.id, peaks);
50	            return next;
51	          });
52	        }
53	      }),
54	    );
55	  }, [sources, pool]); // eslint-disable-line react-hooks/exhaustive-deps
56	
57	  const handleImport = useCallback(
58	    async (files: File[]) => {
59	      if (importingRef.current) return;
60	      importingRef.current = true;
61	      setIsImporting(true);
62	      setErrors([]);
63	      try {
64	        const importErrors: MediaPoolError[] = [];
65	        for (const file of files) {
66	          const result = await pool.importFile(file);
67	          if (result.ok) {
68	            const peaks = await pool.getPeaks(result.handle.id, 256);
69	            if (peaks !== undefined) {
70	              setPeaksMap((prev) => {
71	                const next = new Map(prev);
72	                next.set(result.handle.id, peaks);
73	                return next;
74	              });
75	            }
76	          } else {
77	            importErrors.push(result.error);
78	          }
79	        }
80	        if (importErrors.length > 0) {
81	          setErrors(importErrors);
82	        }
83	        setVersion((v) => v + 1);
84	      } finally {
85	        importingRef.current = false;
86	        setIsImporting(false);
87	      }
88	    },
89	    [pool],
90	  );
91	
92	  const handleRemove = useCallback(
93	    (id: string) => {
94	      void pool.removeSource(id).then(() => {
95	        setVersion((v) => v + 1);
96	        setPeaksMap((prev) => {
97	          const next = new Map(prev);
98	          next.delete(id);
99	          return next;
100	        });
101	      });
102	    },
103	    [pool],
104	  );
105	
106	  const onFileDrop = useCallback(
107	    (files: File[]) => {
108	      void handleImport(files);
109	    },
110	    [handleImport],
111	  );
112	
113	  const { isDragging, handlers } = useFileDrop(onFileDrop);
114	
115	  const onImportClick = useCallback(() => {
116	    fileInputRef.current?.click();
117	  }, []);
118	
119	  const onFileChange = useCallback(
120	    (e: React.ChangeEvent<HTMLInputElement>) => {
121	      const files = e.target.files;
122	      if (files !== null && files.length > 0) {
123	        void handleImport([...files]);
124	      }
125	    },
126	    [handleImport],
127	  );
128	
129	  const panelClass = isDragging
130	    ? [styles["panel"], styles["dragging"]].join(" ")
131	    : (styles["panel"] ?? "");
132	
133	  return (
134	    <section
135	      data-testid="media-pool-panel"
136	      className={panelClass}
137	      {...handlers}
138	    >
139	      <div className={styles["header"]}>
140	        <span>MEDIA POOL</span>
141	        <button
142	          type="button"
143	          className={styles["importBtn"]}
144	          onClick={onImportClick}
145	          disabled={isImporting}
146	        >
147	          {isImporting ? "IMPORTING..." : "IMPORT"}
148	        </button>
149	        <input
150	          ref={fileInputRef}
151	          type="file"
152	          accept="audio/wav,audio/mpeg,audio/ogg,audio/flac,.wav,.mp3,.ogg,.flac"
153	          multiple
154	          style={{ display: "none" }}
155	          onChange={onFileChange}
156	        />
157	      </div>
158	
159	      {errors.length > 0 && (
160	        <div className={styles["error"]}>
161	          {errors.map((err, i) => (
162	            <div key={i}>{formatError(err)}</div>
163	          ))}
164	        </div>
165	      )}
166	
167	      {isImporting && (
168	        <div className={styles["importing"]}>
169	          <Spinner />
170	          <span>Importing audio...</span>
171	        </div>
172	      )}
173	
174	      {sources.length === 0 ? (
175	        <div className={styles["empty"]}>
176	          Drop audio files here or click IMPORT
177	        </div>
178	      ) : (
179	        <div className={styles["list"]}>
180	          {sources.map((source) => (
181	            <MediaPoolItem
182	              key={source.id}
183	              source={source}
184	              peaks={peaksMap.get(source.id)}
185	              onRemove={handleRemove}
186	            />
187	          ))}
188	        </div>
189	      )}
190	    </section>
191	  );
192	}
