1	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
2	import {
3	  isCrossOriginIsolated,
4	  createAudioEngine,
5	  createMediaPool,
6	  createIndexedDBStorage,
7	  type AudioEngineContext,
8	  type MediaPool,
9	} from "@audio/index";
10	import { AudioEngineProvider } from "@audio/audio-engine-provider";
11	import { MediaPoolProvider } from "@audio/media-pool/media-pool-provider";
12	import { CrossOriginError, ClickToStart, DawShell } from "@ui/index";
13	import { ErrorBoundary } from "@ui/ErrorBoundary";
14	import { useDawStore } from "@state/index";
15	import { createIndexedDBSessionStorage } from "@state/session/index";
16	
17	export function App(): React.JSX.Element {
18	  const crossOriginOk = isCrossOriginIsolated();
19	  const [engine, setEngine] = useState<AudioEngineContext | null>(null);
20	  const [pool, setPool] = useState<MediaPool | null>(null);
21	  const engineRef = useRef<AudioEngineContext | null>(null);
22	  const setEngineStatus = useDawStore((s) => s.setEngineStatus);
23	  const sessionStorage = useMemo(() => createIndexedDBSessionStorage(), []);
24	
25	  useEffect(() => {
26	    if (engine === null) return;
27	    const storage = createIndexedDBStorage();
28	    const p = createMediaPool(engine.ctx, storage);
29	    let cancelled = false;
30	    p.init().then(
31	      () => {
32	        if (!cancelled) setPool(p);
33	      },
34	      () => {
35	        // IDB init failed -- pool works but starts empty
36	        if (!cancelled) setPool(p);
37	      },
38	    );
39	    return () => {
40	      cancelled = true;
41	      setPool(null);
42	    };
43	  }, [engine]);
44	
45	  const handleStart = useCallback((): void => {
46	    if (engineRef.current) return;
47	
48	    let newEngine: AudioEngineContext;
49	    try {
50	      newEngine = createAudioEngine();
51	    } catch {
52	      setEngineStatus("error");
53	      return;
54	    }
55	
56	    engineRef.current = newEngine;
57	    newEngine.resume().then(
58	      () => {
59	        if (engineRef.current !== newEngine) return;
60	        setEngineStatus("running");
61	        setEngine(newEngine);
62	      },
63	      () => {
64	        void newEngine.close();
65	        if (engineRef.current === newEngine) {
66	          engineRef.current = null;
67	        }
68	        setEngineStatus("error");
69	      },
70	    );
71	  }, [setEngineStatus]);
72	
73	  useEffect(() => {
74	    return () => {
75	      void engineRef.current?.close();
76	      engineRef.current = null;
77	    };
78	  }, []);
79	
80	  if (!crossOriginOk) {
81	    return <CrossOriginError />;
82	  }
83	
84	  if (engine === null || pool === null) {
85	    return <ClickToStart onStart={handleStart} />;
86	  }
87	
88	  return (
89	    <ErrorBoundary>
90	      <AudioEngineProvider engine={engine}>
91	        <MediaPoolProvider pool={pool}>
92	          <DawShell sessionStorage={sessionStorage} />
93	        </MediaPoolProvider>
94	      </AudioEngineProvider>
95	    </ErrorBoundary>
96	  );
97	}
