1	import { useEffect, useState } from "react";
2	import styles from "./ActionToast.module.css";
3	
4	const TOAST_DURATION = 1200;
5	const FADE_DURATION = 100;
6	
7	type ActionToastProps = {
8	  message: string | null;
9	};
10	
11	type Phase = "visible" | "fading" | "hidden";
12	
13	export function ActionToast({
14	  message,
15	}: ActionToastProps): React.JSX.Element | null {
16	  const [phase, setPhase] = useState<Phase>("hidden");
17	
18	  useEffect(() => {
19	    if (message === null) return;
20	    // Phase starts as "visible" via the setState calls in timeouts below.
21	    // The initial render after message change shows "visible" because
22	    // we schedule state transitions:
23	    const showTimer = setTimeout(() => {
24	      setPhase("visible");
25	    }, 0);
26	
27	    const fadeTimer = setTimeout(() => {
28	      setPhase("fading");
29	    }, TOAST_DURATION - FADE_DURATION);
30	
31	    const hideTimer = setTimeout(() => {
32	      setPhase("hidden");
33	    }, TOAST_DURATION);
34	
35	    return () => {
36	      clearTimeout(showTimer);
37	      clearTimeout(fadeTimer);
38	      clearTimeout(hideTimer);
39	    };
40	  }, [message]);
41	
42	  if (phase === "hidden" || message === null) return null;
43	
44	  const toastClass = styles["toast"] ?? "";
45	  const hidingClass = styles["hiding"] ?? "";
46	  const displayText = message.replace(/#\d+$/, "");
47	
48	  return (
49	    <div
50	      className={`${toastClass}${phase === "fading" ? ` ${hidingClass}` : ""}`}
51	      role="status"
52	      aria-live="polite"
53	    >
54	      {displayText}
55	    </div>
56	  );
57	}
