1	import { useCallback, useEffect, useRef, useState } from "react";
2	
3	type BpmInputProps = {
4	  value: number;
5	  onChange: (bpm: number) => void;
6	};
7	
8	const BPM_MIN = 20;
9	const BPM_MAX = 999;
10	
11	export function BpmInput({
12	  value,
13	  onChange,
14	}: BpmInputProps): React.JSX.Element {
15	  const [localValue, setLocalValue] = useState(String(value));
16	  const inputRef = useRef<HTMLInputElement>(null);
17	
18	  // Sync external value changes
19	  useEffect(() => {
20	    setLocalValue(String(value));
21	  }, [value]);
22	
23	  const commit = useCallback((): void => {
24	    const parsed = Number(localValue);
25	    if (!Number.isFinite(parsed) || localValue.trim() === "") {
26	      setLocalValue(String(value));
27	      return;
28	    }
29	    const clamped = Math.min(BPM_MAX, Math.max(BPM_MIN, Math.round(parsed)));
30	    setLocalValue(String(clamped));
31	    onChange(clamped);
32	  }, [localValue, value, onChange]);
33	
34	  const handleKeyDown = useCallback(
35	    (e: React.KeyboardEvent<HTMLInputElement>): void => {
36	      if (e.key === "Enter") {
37	        commit();
38	        inputRef.current?.blur();
39	      } else if (e.key === "Escape") {
40	        setLocalValue(String(value));
41	        inputRef.current?.blur();
42	      }
43	    },
44	    [commit, value],
45	  );
46	
47	  return (
48	    <input
49	      ref={inputRef}
50	      type="number"
51	      aria-label="BPM"
52	      value={localValue}
53	      min={BPM_MIN}
54	      max={BPM_MAX}
55	      onChange={(e) => {
56	        setLocalValue(e.target.value);
57	      }}
58	      onBlur={commit}
59	      onKeyDown={handleKeyDown}
60	      style={{
61	        width: "56px",
62	        backgroundColor: "var(--color-black)",
63	        color: "var(--color-white)",
64	        border: "var(--border)",
65	        fontFamily: "var(--font-mono)",
66	        fontSize: "var(--text-sm)",
67	        padding: "var(--space-1) var(--space-2)",
68	        textAlign: "center",
69	      }}
70	    />
71	  );
72	}
