2	
3	type Props = {
4	  children: ReactNode;
5	  fallbackLabel?: string;
6	};
7	
8	type State = {
9	  error: Error | null;
10	};
11	
12	export class ErrorBoundary extends Component<Props, State> {
13	  override state: State = { error: null };
14	
15	  static getDerivedStateFromError(error: Error): State {
16	    return { error };
17	  }
18	
19	  override componentDidCatch(error: Error, info: ErrorInfo): void {
20	    console.error("[ErrorBoundary]", error, info.componentStack);
21	  }
22	
23	  override render(): ReactNode {
24	    const { error } = this.state;
25	    if (error === null) {
26	      return this.props.children;
27	    }
28	
29	    const label = this.props.fallbackLabel ?? "Something went wrong";
30	
31	    return (
32	      <div
33	        role="alert"
34	        style={{
35	          display: "flex",
36	          flexDirection: "column",
37	          alignItems: "center",
38	          justifyContent: "center",
39	          padding: "2rem",
