61	            window.location.reload();
62	          }}
63	          style={{
64	            padding: "0.5rem 1.5rem",
65	            border: "var(--border-width) solid var(--color-red)",
66	            background: "transparent",
67	            color: "var(--color-red)",
68	            cursor: "pointer",
69	            fontSize: "0.875rem",
70	          }}
71	        >
72	          Reload
73	        </button>
74	      </div>
75	    );
76	  }
77	}
