50	  return view.headerWidth + (seconds - view.scrollX) * view.pixelsPerSecond;
51	}
52	
53	function trackY(index: number, view: ArrangementViewState): number {
54	  return RULER_HEIGHT + index * view.trackHeight - view.scrollY;
55	}
56	
57	/** Convert a hex color (#rrggbb) to rgba with given alpha (0-1). */
58	function hexToRgba(hex: string, alpha: number): string {
59	  if (!/^#[0-9a-fA-F]{6}$/.test(hex)) {
60	    return `rgba(128,128,128,${String(alpha)})`;
61	  }
62	  const r = parseInt(hex.slice(1, 3), 16);
63	  const g = parseInt(hex.slice(3, 5), 16);
64	  const b = parseInt(hex.slice(5, 7), 16);
65	  return `rgba(${String(r)},${String(g)},${String(b)},${String(alpha)})`;
66	}
67	
68	// -- Rendering stages ---------------------------------------------------------
69	
70	function drawBackground(rc: RenderContext): void {
71	  const { ctx, width, height } = rc;
72	  ctx.fillStyle = COLOR.gray900;
73	  ctx.fillRect(0, 0, width, height);
74	}
75	
76	function drawTimeRuler(rc: RenderContext): void {
77	  const { ctx, width, view, bpm } = rc;
78	  const secPerBeat = 60 / bpm;
79	  const secPerBar = secPerBeat * 4;
80	
81	  // Ruler background
82	  ctx.fillStyle = COLOR.black;
83	  ctx.fillRect(0, 0, width, RULER_HEIGHT);
84	
85	  // Bar labels
86	  ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
87	  ctx.fillStyle = COLOR.gray500;
88	  ctx.textBaseline = "middle";
89	  ctx.textAlign = "center";
90	
91	  const startBar = Math.max(0, Math.floor(view.scrollX / secPerBar));
92	  const endSec =
93	    view.scrollX + (width - view.headerWidth) / view.pixelsPerSecond;
94	  const endBar = Math.ceil(endSec / secPerBar) + 1;
95	
96	  for (let bar = startBar; bar < endBar; bar++) {
97	    const x = secondsToX(bar * secPerBar, view);
98	    if (x >= view.headerWidth && x <= width) {
99	      ctx.fillText(String(bar + 1), x, RULER_HEIGHT / 2);
100	    }
101	  }
102	}
103	
104	function drawGrid(rc: RenderContext): void {
105	  const { ctx, width, height, view, bpm } = rc;
106	  const secPerBeat = 60 / bpm;
107	  const secPerBar = secPerBeat * 4;
108	
109	  // Determine visible range in seconds
110	  const startSec = view.scrollX;
111	  const endSec =
112	    view.scrollX + (width - view.headerWidth) / view.pixelsPerSecond;
113	
114	  // Determine grid step -- skip beats when zoomed out too far
115	  const minPxPerLine = 12;
116	  let step = secPerBeat;
117	  while (step * view.pixelsPerSecond < minPxPerLine) {
118	    step *= 2;
119	  }
120	
121	  const firstBeat = Math.floor(startSec / step) * step;
122	
123	  ctx.save();
124	  for (let t = firstBeat; t <= endSec; t += step) {
125	    const x = secondsToX(t, view);
126	    if (x < view.headerWidth || x > width) continue;
127	
128	    // Check if this line sits on a bar boundary (use integer arithmetic to avoid float drift)
129	    const nearestBar = Math.round(t / secPerBar) * secPerBar;
130	    const isBar = Math.abs(t - nearestBar) < 0.001;
131	    ctx.strokeStyle = COLOR.gray700;
132	    ctx.lineWidth = isBar ? 2 : 1;
133	
134	    ctx.beginPath();
135	    ctx.moveTo(x, RULER_HEIGHT);
136	    ctx.lineTo(x, height);
137	    ctx.stroke();
138	  }
139	  ctx.restore();
140	}
141	
142	function drawTrackLanes(rc: RenderContext): void {
143	  const { ctx, width, view, tracks } = rc;
144	
145	  for (let i = 0; i < tracks.length; i++) {
146	    const y = trackY(i, view);
147	    const bottom = y + view.trackHeight;
148	
149	    if (bottom < RULER_HEIGHT || y > rc.height) continue;
150	
151	    // Lane separator
152	    ctx.strokeStyle = COLOR.gray700;
153	    ctx.lineWidth = BORDER_WIDTH;
154	    ctx.beginPath();
155	    ctx.moveTo(0, bottom);
156	    ctx.lineTo(width, bottom);
157	    ctx.stroke();
158	  }
159	}
160	
161	function drawTrackHeaders(rc: RenderContext): void {
162	  const { ctx, view, tracks } = rc;
163	
164	  for (let i = 0; i < tracks.length; i++) {
165	    const track = tracks[i];
166	    if (track === undefined) continue;
167	    const y = trackY(i, view);
168	
169	    if (y + view.trackHeight < RULER_HEIGHT || y > rc.height) continue;
170	
171	    // Header background
172	    ctx.fillStyle = COLOR.black;
173	    ctx.fillRect(0, y, view.headerWidth, view.trackHeight);
174	
175	    // Color strip (4px vertical bar)
176	    ctx.fillStyle = track.color;
177	    ctx.fillRect(0, y, COLOR_STRIP_WIDTH, view.trackHeight);
178	
179	    // Track name
180	    ctx.font = `${String(TEXT_SM)}px ${FONT_MONO}`;
181	    ctx.fillStyle = COLOR.white;
182	    ctx.textBaseline = "middle";
183	    ctx.textAlign = "left";
184	    ctx.fillText(track.name, COLOR_STRIP_WIDTH + 8, y + view.trackHeight / 2);
185	
186	    // Mute/Solo indicators
187	    const indicatorY = y + view.trackHeight / 2;
188	    ctx.font = `bold ${String(TEXT_XS)}px ${FONT_MONO}`;
189	    ctx.textAlign = "center";
190	
191	    if (track.muted) {
192	      ctx.fillStyle = COLOR.gray500;
193	      ctx.fillText("M", view.headerWidth - 36, indicatorY);
194	    }
195	    if (track.solo) {
196	      ctx.fillStyle = COLOR.gray500;
197	      ctx.fillText("S", view.headerWidth - 18, indicatorY);
198	    }
199	
200	    // Header right border
201	    ctx.strokeStyle = COLOR.gray700;
202	    ctx.lineWidth = BORDER_WIDTH;
203	    ctx.beginPath();
204	    ctx.moveTo(view.headerWidth, y);
205	    ctx.lineTo(view.headerWidth, y + view.trackHeight);
206	    ctx.stroke();
207	  }
208	}
209	
210	function drawClips(rc: RenderContext): void {
211	  const { ctx, view, tracks, clips, selectedClipIds } = rc;
212	  const selectedSet = new Set(selectedClipIds);
213	
214	  for (let i = 0; i < tracks.length; i++) {
215	    const track = tracks[i];
216	    if (track === undefined) continue;
217	    const y = trackY(i, view);
218	
219	    if (y + view.trackHeight < RULER_HEIGHT || y > rc.height) continue;
220	
221	    for (const clipId of track.clipIds) {
222	      const clip = clips[clipId];
223	      if (clip === undefined) continue;
224	
225	      const x = secondsToX(clip.startTime, view);
226	      const w = clip.duration * view.pixelsPerSecond;
227	
228	      // Skip clips that are fully out of view
229	      if (x + w < view.headerWidth || x > rc.width) continue;
230	
231	      const clipY = y + CLIP_PADDING;
232	      const clipH = view.trackHeight - CLIP_PADDING * 2;
233	
234	      // Clip fill (track color at 60% opacity)
235	      ctx.fillStyle = hexToRgba(track.color, 0.6);
236	      ctx.fillRect(x, clipY, w, clipH);
237	
238	      // Clip border
239	      const isSelected = selectedSet.has(clip.id);
240	      ctx.strokeStyle = isSelected ? COLOR.white : track.color;
241	      ctx.lineWidth = BORDER_WIDTH;
242	      ctx.strokeRect(x, clipY, w, clipH);
243	
244	      // Clip name label
245	      ctx.save();
246	      ctx.beginPath();
247	      ctx.rect(x, clipY, w, clipH);
248	      ctx.clip();
249	      ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
250	      ctx.fillStyle = COLOR.white;
251	      ctx.textBaseline = "top";
252	      ctx.textAlign = "left";
253	      ctx.fillText(clip.name, x + 4, clipY + 4);
254	      ctx.restore();
255	    }
256	  }
257	}
258	
259	function drawPlayhead(rc: RenderContext): void {
260	  const { ctx, height, view, cursorSeconds } = rc;
261	  const x = secondsToX(cursorSeconds, view);
262	
263	  if (x < view.headerWidth || x > rc.width) return;
264	
265	  ctx.strokeStyle = COLOR.red;
266	  ctx.lineWidth = 2;
267	  ctx.beginPath();
268	  ctx.moveTo(x, 0);
269	  ctx.lineTo(x, height);
270	  ctx.stroke();
271	}
272	
273	// -- Public API ---------------------------------------------------------------
274	
275	export function renderArrangement(rc: RenderContext): void {
276	  drawBackground(rc);
277	  drawTimeRuler(rc);
278	  drawGrid(rc);
279	  drawTrackLanes(rc);
280	  drawTrackHeaders(rc);
281	  drawClips(rc);
282	  drawPlayhead(rc);
283	}
284

