      ctx.fillText("S", view.headerWidth - 18, indicatorY);
    }

    // Header right border
    ctx.strokeStyle = COLOR.gray700;
    ctx.lineWidth = BORDER_WIDTH;
    ctx.beginPath();
    ctx.moveTo(view.headerWidth, y);
    ctx.lineTo(view.headerWidth, y + view.trackHeight);
    ctx.stroke();
  }
}

function drawClips(rc: RenderContext): void {
  const { ctx, view, tracks, clips, selectedClipIds } = rc;
  const selectedSet = new Set(selectedClipIds);

  for (let i = 0; i < tracks.length; i++) {
    const track = tracks[i];
    if (track === undefined) continue;
    const y = trackY(i, view);

    if (y + view.trackHeight < RULER_HEIGHT || y > rc.height) continue;

    for (const clipId of track.clipIds) {
      const clip = clips[clipId];
      if (clip === undefined) continue;

      const x = secondsToX(clip.startTime, view);
      const w = clip.duration * view.pixelsPerSecond;

      // Skip clips that are fully out of view
      if (x + w < view.headerWidth || x > rc.width) continue;

      const clipY = y + CLIP_PADDING;
      const clipH = view.trackHeight - CLIP_PADDING * 2;

      // Clip fill (track color at 60% opacity)
      ctx.fillStyle = hexToRgba(track.color, 0.6);
      ctx.fillRect(x, clipY, w, clipH);

      // Clip border
      const isSelected = selectedSet.has(clip.id);
      ctx.strokeStyle = isSelected ? COLOR.white : track.color;
      ctx.lineWidth = BORDER_WIDTH;
      ctx.strokeRect(x, clipY, w, clipH);

      // Clip name label
      ctx.save();
      ctx.beginPath();
      ctx.rect(x, clipY, w, clipH);
      ctx.clip();
      ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
      ctx.fillStyle = COLOR.white;
      ctx.textBaseline = "top";
      ctx.textAlign = "left";
      ctx.fillText(clip.name, x + 4, clipY + 4);
      ctx.restore();
    }
  }
}

function drawPlayhead(rc: RenderContext): void {
  const { ctx, height, view, cursorSeconds } = rc;
  const x = secondsToX(cursorSeconds, view);

  if (x < view.headerWidth || x > rc.width) return;

  ctx.strokeStyle = COLOR.red;
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(x, 0);
  ctx.lineTo(x, height);
  ctx.stroke();
}

// -- Public API ---------------------------------------------------------------

export function renderArrangement(rc: RenderContext): void {
  drawBackground(rc);
  drawTimeRuler(rc);
  drawGrid(rc);
  drawTrackLanes(rc);
  drawTrackHeaders(rc);
  drawClips(rc);
  drawPlayhead(rc);
}

import { useCallback, useState } from "react";
import { useTransport } from "@audio/use-transport";
import { useDawStore } from "@state/index";
import { BpmInput } from "./BpmInput";
import { CursorDisplay } from "./CursorDisplay";
import styles from "./TransportBar.module.css";

export function TransportBar(): React.JSX.Element {
  const transport = useTransport();
  const transportState = useDawStore((s) => s.transportState);
  const bpm = useDawStore((s) => s.bpm);
  const loopEnabled = useDawStore((s) => s.loopEnabled);
  const setLoop = useDawStore((s) => s.setLoop);
  const [metronomeOn, setMetronomeOn] = useState(false);

  const handleLoopToggle = useCallback((): void => {
    setLoop(!loopEnabled);
  }, [loopEnabled, setLoop]);

  const handleMetronomeToggle = useCallback((): void => {
    const next = !metronomeOn;
    setMetronomeOn(next);
    transport.setMetronomeEnabled(next);
  }, [metronomeOn, transport]);

  const handleBpmChange = useCallback(
    (newBpm: number): void => {
      transport.setBpm(newBpm);
    },
    [transport],
  );

  const isPlaying = transportState === "playing";
  const clock = transport.getClock();
  const tempoMap = clock?.getTempoMap() ?? null;

  return (
    <header data-testid="toolbar" className={styles["transportBar"]}>
      <span className={styles["brand"]}>BRUTALWAV</span>
      <div className={styles["spacer"]} />

      <div className={styles["controls"]}>
        <span className={styles["label"]}>BPM</span>
        <BpmInput value={bpm} onChange={handleBpmChange} />

        <span className={styles["label"]}>4/4</span>

        <button
          type="button"
          className={styles["transportBtn"]}
          aria-pressed={isPlaying}
          aria-label="Play"
          onClick={() => {
            transport.play();
          }}
        >
          {"\u25B6"}
        </button>

        <button
          type="button"
          className={styles["transportBtn"]}
          aria-label="Stop"
          onClick={() => {
            transport.stop();
          }}
        >
          {"\u25A0"}
        </button>

        <CursorDisplay
          transportSAB={transport.getTransportSAB()}
          tempoMap={tempoMap}
        />

        <button
          type="button"
          role="switch"
          aria-checked={loopEnabled}
          aria-label="Loop"
          className={styles["transportBtn"]}
          data-active={loopEnabled}
          onClick={handleLoopToggle}
        >
          LOOP
        </button>

        <div className={styles["metronomeToggle"]}>
          <button
            type="button"
            role="switch"
            aria-checked={metronomeOn}
            aria-label="Metronome"
            className={styles["transportBtn"]}
            data-active={metronomeOn}
            onClick={handleMetronomeToggle}
          >
            MET
          </button>
        </div>
      </div>
    </header>
  );
}

